{"code": "import json
import re

# Load package info JSON (largest)
path1 = var_functions.query_db:14
with open(path1, 'r') as f:
    pkg_info_records = json.load(f)  # should be list of dicts

# Load project_packageversion
path2 = var_functions.query_db:16
with open(path2, 'r') as f:
    proj_pkg_ver_records = json.load(f)

# For each distinct NPM package, find highest ordinal release version
# Key: (System, Name)
latest_versions = {}
count = 0
for rec in pkg_info_records:
    if rec.get('System') != 'NPM':
        continue
    # parse VersionInfo JSON string
    vi_str = rec.get('VersionInfo', '{}')
    try:
        vi = json.loads(vi_str)
    except Exception:
        continue
    if not vi.get('IsRelease'):
        continue
    ordinal = vi.get('Ordinal', 0)
    key = (rec.get('System'), rec.get('Name'))
    # Keep if higher ordinal
    if key not in latest_versions or ordinal > latest_versions[key]['ordinal']:
        latest_versions[key] = {'version': rec.get('Version'), 'ordinal': ordinal, 'record': rec}

# Build mapping from (Name, Version) to ProjectName via project_packageversion
proj_map = {}
for rec in proj_pkg_ver_records:
    if rec.get('System') != 'NPM':
        continue
    proj_map[(rec.get('Name'), rec.get('Version'))] = rec.get('ProjectName')

# Now build list of packages with project name
packages_with_proj = []
for (system, name), info in latest_versions.items():
    ver = info['version']
    proj_name = proj_map.get((name, ver))
    if proj_name:
        packages_with_proj.append({
            'name': name,
            'version': ver,
            'project_name': proj_name,
            'ordinal': info['ordinal']
        })

# Save for later
with open('/tmp/packages_with_proj.json', 'w') as f:
    json.dump(packages_with_proj, f, indent=2)

print("__RESULT__:")
print(json.dumps({
    'total_latest_release_packages': len(packages_with_proj),
    'sample': packages_with_proj[:5]
}, indent=2))"}

